CREATE TABLE J09C_sales_present AS
SELECT DISTINCT EQUNR
FROM sales_master;

UPDATE J09C_working
SET 
  TITLE = CASE WHEN CUSTOMER_SOURCE = 'SALES' THEN (
    SELECT s.TITLE FROM sales_master s WHERE s.EQUNR = J09C_working.EQUNR LIMIT 1
  ) ELSE (
    SELECT n.TITLE FROM net_master n WHERE n.EQUNR = J09C_working.EQUNR LIMIT 1
  ) END,
